  "exercises": [
    {
      "words": ["Je", "vais", "à", "Paris."],
      "translation": "Ich fahre nach Paris.",
      "explanation": "Bei A1-Sätzen folgt die Wortstellung in der Regel dem einfachen SVO-System: Subjekt (Je), Verb (vais) und Dativobjekt (à Paris)."
    },
    {
      "words": ["Tu", "as", "un", "chien."],
      "translation": "Du hast einen Hund.",
      "explanation": "Das Verb 'avoir' (haben) steht nach dem Subjekt. Bei der Verneinung wird 'ne...pas' verwendet, aber hier ist es positiv: Tu as un chien."
    },
    {
      "words": ["Elle", "aime", "l'eau."],
      "translation": "Sie mag das Wasser.",
      "explanation": "Das Subjekt (Elle) kommt vor dem Verb 'aimer' (mögen), gefolgt von dem direkten Objekt (l'eau)."
    },
    {
      "words": ["Nous", "sommes", "à", "la", "maison."],
      "translation": "Wir sind zu Hause.",
      "explanation": "Das Verb 'être' (sein) steht nach dem Subjekt. 'À la maison' ist ein fester Ausdruck, der mit 'être' verwendet wird."
    },
    {
      "words": ["Vous", "avez", "de", "l'eau."],
      "translation": "Ihr habt Wasser.",
      "explanation": "Das Subjekt (Vous) steht vor dem Verb 'avoir'. 'De l'eau' bedeutet 'Wasser', wobei 'de' im unbestimmten Artikel verwendet wird."
    }
  ]
}
